// Group active trackers by chat_id and enrich with yesterday prices
const trackerItems = $('Read All Trackers').all();
const historyItems = $('Read Price History').all();

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const yesterdayStr = yesterday.toISOString().split('T')[0];

// Build price history lookup: tracker_id -> yesterday price
const yesterdayPrices = {};
for (const h of historyItems) {
  const ts = h.json.timestamp || '';
  if (ts.startsWith(yesterdayStr)) {
    const tid = h.json.tracker_id;
    if (!yesterdayPrices[tid]) {
      yesterdayPrices[tid] = parseFloat(h.json.price);
    }
  }
}

// Group active trackers by chat_id
const grouped = {};
for (const item of trackerItems) {
  const row = item.json;
  if (row.status !== 'active') continue;
  const cid = row.chat_id;
  if (!grouped[cid]) grouped[cid] = [];
  grouped[cid].push({
    ...row,
    yesterday_price: yesterdayPrices[row.tracker_id] || null
  });
}

return Object.entries(grouped).map(([chat_id, trackers]) => ({
  chat_id,
  trackers,
  email_alerts: trackers[0].email_alerts,
  email_address: trackers[0].email_address,
  whatsapp_number: trackers[0].whatsapp_number || ''
}));

// Fetch current price for each tracker route belonging to this user
const token = $input.first().json.access_token;
if (!token) throw new Error('No Amadeus access token');

const userCtx = $('Loop Over Users').first().json;
const trackers = userCtx.trackers;

const updatedTrackers = [];

for (const tracker of trackers) {
  let currentPrice = null;
  let airline = '';

  try {
    const returnParam = tracker.return_date && tracker.return_date !== 'ONEWAY'
      ? `&returnDate=${tracker.return_date}` : '';
    const url = `https://test.api.amadeus.com/v2/shopping/flight-offers?originLocationCode=${tracker.from_airport}&destinationLocationCode=${tracker.to_airport}&departureDate=${tracker.travel_date}${returnParam}&adults=${tracker.passengers || 1}&max=1&currencyCode=${tracker.currency || 'CAD'}`;

    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url,
      headers: { Authorization: `Bearer ${token}` }
    });

    if (resp.data && resp.data.length > 0) {
      currentPrice = parseFloat(resp.data[0].price.total);
      airline = resp.data[0].validatingAirlineCodes[0];
    }
  } catch (e) {
    // Continue with null price if this route fails
  }

  updatedTrackers.push({ ...tracker, current_price: currentPrice, airline });
}

return [{
  chat_id: userCtx.chat_id,
  email_alerts: userCtx.email_alerts,
  email_address: userCtx.email_address,
  whatsapp_number: userCtx.whatsapp_number,
  trackers: updatedTrackers
}];

// Build multi-route digest message
const d = $input.first().json;
const currentDate = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

let message = `Daily Flight Price Report – ${currentDate}\n`;
message += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

for (const tracker of d.trackers) {
  const daysSince = Math.floor((new Date() - new Date(tracker.tracking_since)) / (1000 * 60 * 60 * 24));
  const curr = tracker.currency || 'CAD';
  const todayPrice = tracker.current_price !== null ? `${curr} ${tracker.current_price.toFixed(2)}` : 'Unavailable';
  const yesterdayPriceStr = tracker.yesterday_price ? `${curr} ${tracker.yesterday_price.toFixed(2)}` : 'N/A';

  message += `✈ ${tracker.from_airport} → ${tracker.to_airport}\n`;
  message += `Today: ${todayPrice} | Yesterday: ${yesterdayPriceStr}\n`;
  message += `Lowest Ever: ${curr} ${tracker.lowest_price} | Tracking: ${daysSince} days\n\n`;
}

message += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`;

return [{ ...d, digest_message: message }];
